/**
 * std-lms — Learning management system organism. Composes molecules via compose: - stdList(Course): CRUD list of courses - stdWizard(Enrollment): multi-step enrollment wizard - stdDisplay(Progress): read-only progress dashboard
 *
 * Autogenerated by scripts/regenerate-std-ts.mjs from
 * packages/almadar-std/behaviors/registry/organisms/std-lms.orb.
 *
 * This is a thin descriptor layer over the canonical .orb. The exported
 * functions return TraitReference / PageRefObject / OrbitalDefinition
 * payloads that reference the sibling .orb via `uses:` + `ref:`. The
 * compiler's inline phase materialises the real trait at build time.
 *
 * Do not hand-edit — regenerate via
 *   node scripts/regenerate-std-ts.mjs --only=std-lms
 *
 * @level organism
 * @packageDocumentation
 */

import type { TraitReference, PageRefObject, OrbitalDefinition, Entity, EntityField } from '@almadar/core/types';
import { makeTraitRef, makePageRef, makeOrbitalWithUses } from '@almadar/core/builders';

const BEHAVIOR_PATH = 'std/behaviors/std-lms';
const ALIAS = 'Lms';

/**
 * Params for the std-lms descriptor helpers.
 *
 * `entityName` binds every trait/page reference's `linkedEntity`.
 * The optional override fields mirror TraitReference / PageRefObject
 * fields and are forwarded to `makeTraitRef` / `makePageRef`.
 */
export interface StdLmsParams {
  entityName: string;
  /** Extra fields to add to the orbital-scoped entity clone. */
  fields?: EntityField[];
  /** Rename the inlined trait at the call site. */
  traitName?: string;
  /** Per-key event rename map (atom key → caller key). */
  events?: Record<string, string>;
  /** Per-event effect replacement (keys are POST-rename event names). */
  effects?: Record<string, unknown[]>;
  /** Replace the imported trait's `listens` array entirely. */
  listens?: unknown[];
  /** Set every emit's scope. */
  emitsScope?: 'internal' | 'external';
  /** Nested config override (outer key = config field name). */
  config?: Record<string, Record<string, unknown>>;
  /** URL path override for the (first) page. */
  pagePath?: string;
}

/** Trait descriptor: `Lms.traits.CourseBrowse`. */
export function stdLmsCourseBrowseTrait(params: StdLmsParams): TraitReference {
  return makeTraitRef({
    from: BEHAVIOR_PATH,
    ref: `${ALIAS}.traits.CourseBrowse`,
    linkedEntity: params.entityName,
    ...(params.traitName !== undefined ? { name: params.traitName } : {}),
    ...(params.events !== undefined ? { events: params.events } : {}),
    ...(params.effects !== undefined ? { effects: params.effects as Record<string, never> } : {}),
    ...(params.listens !== undefined ? { listens: params.listens as never } : {}),
    ...(params.emitsScope !== undefined ? { emitsScope: params.emitsScope } : {}),
    ...(params.config !== undefined ? { config: params.config } : {}),
  });
}

