/** Whole-orbital descriptor (3 orbitals). */
export function stdLms(params: StdLmsParams): OrbitalDefinition[] {
  const entity: Entity = {
    name: params.entityName,
    fields: params.fields ?? [],
  };
  return [
    makeOrbitalWithUses({
      name: 'CourseOrbital',
      uses: [{ from: BEHAVIOR_PATH, as: ALIAS }],
      entity,
      traits: [
        makeTraitRef({ from: BEHAVIOR_PATH, ref: `${ALIAS}.traits.CourseBrowse`, linkedEntity: params.entityName }),
        makeTraitRef({ from: BEHAVIOR_PATH, ref: `${ALIAS}.traits.CourseCreate`, linkedEntity: params.entityName }),
        makeTraitRef({ from: BEHAVIOR_PATH, ref: `${ALIAS}.traits.CourseEdit`, linkedEntity: params.entityName }),
        makeTraitRef({ from: BEHAVIOR_PATH, ref: `${ALIAS}.traits.CourseView`, linkedEntity: params.entityName }),
        makeTraitRef({ from: BEHAVIOR_PATH, ref: `${ALIAS}.traits.CourseDelete`, linkedEntity: params.entityName }),
      ],
      pages: [
        makePageRef({ from: BEHAVIOR_PATH, ref: `${ALIAS}.pages.CoursesPage`, linkedEntity: params.entityName }),
      ],
    }),
    makeOrbitalWithUses({
      name: 'EnrollmentOrbital',
      uses: [{ from: BEHAVIOR_PATH, as: ALIAS }],
      entity,
      traits: [
        makeTraitRef({ from: BEHAVIOR_PATH, ref: `${ALIAS}.traits.EnrollmentWizard`, linkedEntity: params.entityName }),
      ],
      pages: [
        makePageRef({ from: BEHAVIOR_PATH, ref: `${ALIAS}.pages.EnrollPage`, linkedEntity: params.entityName }),
      ],
    }),
    makeOrbitalWithUses({
      name: 'ProgressOrbital',
      uses: [{ from: BEHAVIOR_PATH, as: ALIAS }],
      entity,
      traits: [
        makeTraitRef({ from: BEHAVIOR_PATH, ref: `${ALIAS}.traits.ProgressDisplay`, linkedEntity: params.entityName }),
      ],
      pages: [
        makePageRef({ from: BEHAVIOR_PATH, ref: `${ALIAS}.pages.ProgressPage`, linkedEntity: params.entityName }),
      ],
    }),
  ];
}
